import { Season } from "../../data/seasons/season";

const SeasonCard = (season : Season) => {
    return(
        <>
            <div className="card">
                <div className="card-body">
                    <h5 className="card-title">Season: {season.startYear + " - " + season.endYear} </h5>
                    <p className="card-text">Age Group: {season.ageGroup}</p>
                </div>
            </div>

        </>
    )
}

export default SeasonCard;
